UPDATE tblLstSpecies INNER JOIN ((((((tblStation INNER JOIN tblStationSubGear ON tblStation.KeyStation = tblStationSubGear.KeyStation) INNER JOIN tblCatch ON tblStationSubGear.KeyStationSubGear = tblCatch.KeyStationSubGear) INNER JOIN tblCatchSub1 ON tblCatch.KeyCatch = tblCatchSub1.KeyCatch) INNER JOIN tblCatchSub2 ON tblCatchSub1.KeyCatchSub1 = tblCatchSub2.KeyCatchSub1) INNER JOIN tblIndividual ON tblCatchSub2.KeyCatchSub2 = tblIndividual.KeyCatchSub2) INNER JOIN tblIndividualMeasure ON tblIndividual.KeyIndividual = tblIndividualMeasure.KeyIndividual) ON tblLstSpecies.Species = tblCatchSub2.Species SET tblIndividualMeasure.Attribute = "M"
WHERE (((tblStation.TripYear)=2026) AND ((tblStation.Ship)="TA") AND ((tblStation.Trip)="2") AND ((tblStation.Station)=50) AND ((tblIndividual.KeyIndividual) In (SELECT [KeyIndividual] FROM [tblIndividualMeasure] WHERE [IndividualMeasureType]="ShrimpRoe" AND [Attribute]="None") And (tblIndividual.KeyIndividual) In (SELECT [KeyIndividual] FROM [tblIndividualMeasure] WHERE [IndividualMeasureType]="EggHair" AND [Attribute]="0") And (tblIndividual.KeyIndividual) In (SELECT [KeyIndividual] FROM [tblIndividualMeasure] WHERE [IndividualMeasureType]="ShrimpSex" AND [Attribute]="FP")) AND ((tblLstSpecies.NameLatin)="Pandalus borealis") AND ((tblIndividualMeasure.IndividualMeasureType)="ShrimpSex") AND ((tblIndividualMeasure.Attribute)="FP"));
